// ─────────────────────────────────────────────────────────────────────────────
// PUBLICAR VEHÍCULO EN FACEBOOK PAGE
// ─────────────────────────────────────────────────────────────────────────────
// Variables requeridas (hardcodeadas o via $vars si tenés licencia):
//   FB_PAGE_ID          : ID numérico de tu Facebook Page
//   FB_PAGE_ACCESS_TOKEN: Page Access Token de larga duración
// ─────────────────────────────────────────────────────────────────────────────

const FB_PAGE_ID = $vars.FB_PAGE_ID;
const FB_PAGE_ACCESS_TOKEN = $vars.FB_PAGE_ACCESS_TOKEN;
const BASE_URL = 'https://graph.facebook.com/v21.0';

if (!FB_PAGE_ID || !FB_PAGE_ACCESS_TOKEN) {
  throw new Error('Faltan variables del workflow. Configurá FB_PAGE_ID y FB_PAGE_ACCESS_TOKEN.');
}

const items = $input.all();
const raw = items[0].json;
const data = raw.body || raw;
const vehicle = data.vehicle;

if (!vehicle) {
  throw new Error('Payload inválido: falta el objeto vehicle.');
}

// ── Construir mensaje ────────────────────────────────────────────────────────
const titulo = vehicle.brand + ' ' + vehicle.model + ' ' + vehicle.year + (vehicle.version ? ' ' + vehicle.version : '');
const km = vehicle.kilometers > 0
  ? vehicle.kilometers.toLocaleString('es-AR') + ' km'
  : '0 km';
const precio = (vehicle.showPrice !== false && vehicle.price && vehicle.price > 0)
  ? vehicle.currency + ' ' + vehicle.price.toLocaleString('es-AR')
  : '';
const featuresList = (vehicle.features && vehicle.features.length > 0)
  ? vehicle.features.slice(0, 5).join(' • ')
  : '';

let message = '🚗 ' + titulo + '\n\n' + (vehicle.description || '');
if (featuresList) message += '\n\n✨ ' + featuresList;
message += '\n\n📍 ' + km;
if (precio) message += '\n💰 ' + precio;
message += '\n\n📲 Consultanos por DM o WhatsApp';

// ── Validar fotos ───────────────────────────────────────────────────────────
const photos = (vehicle.photos || [])
  .filter(function(p) { return typeof p === 'string' && p.startsWith('http'); })
  .slice(0, 10);

if (photos.length === 0) {
  throw new Error('No hay fotos públicas (URLs http/https) disponibles para publicar en Facebook.');
}

try {
  let postId;

  if (photos.length === 1) {
    // ── Post con imagen única ──────────────────────────────────────────────
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: BASE_URL + '/' + FB_PAGE_ID + '/photos',
      qs: {
        url: photos[0],
        caption: message,
        access_token: FB_PAGE_ACCESS_TOKEN
      }
    });

    if (!res.id) {
      throw new Error('Error al publicar foto: ' + JSON.stringify(res));
    }
    postId = res.post_id || res.id;

  } else {
    // ── Post con álbum (2–10 fotos) ────────────────────────────────────────
    // Paso 1: subir cada foto sin publicar para obtener su media_fbid
    const mediaIds = [];

    for (var i = 0; i < photos.length; i++) {
      const photoRes = await this.helpers.httpRequest({
        method: 'POST',
        url: BASE_URL + '/' + FB_PAGE_ID + '/photos',
        qs: {
          url: photos[i],
          published: 'false',
          access_token: FB_PAGE_ACCESS_TOKEN
        }
      });

      if (!photoRes.id) {
        throw new Error('Error al subir foto ' + (i + 1) + ': ' + JSON.stringify(photoRes));
      }
      mediaIds.push({ media_fbid: photoRes.id });
    }

    // Paso 2: crear el post con todas las fotos adjuntas
    const postRes = await this.helpers.httpRequest({
      method: 'POST',
      url: BASE_URL + '/' + FB_PAGE_ID + '/feed',
      qs: {
        message: message,
        attached_media: JSON.stringify(mediaIds),
        access_token: FB_PAGE_ACCESS_TOKEN
      }
    });

    if (!postRes.id) {
      throw new Error('Error al crear post con álbum: ' + JSON.stringify(postRes));
    }
    postId = postRes.id;
  }

  return [{
    json: {
      success: true,
      externalId: postId,
      vehicleId: vehicle.id,
      platform: 'facebook',
      action: 'published',
      message: 'Publicación creada exitosamente en Facebook',
      publishedAt: new Date().toISOString(),
      photoCount: photos.length,
      postType: photos.length === 1 ? 'single' : 'album'
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      vehicleId: vehicle ? vehicle.id : null,
      platform: 'facebook',
      action: 'publish'
    }
  }];
}

// ─────────────────────────────────────────────────────────────────────────────
// PAUSAR PUBLICACIÓN EN FACEBOOK
// ─────────────────────────────────────────────────────────────────────────────
// Facebook Graph API no soporta ocultar posts de página via API pública.
// Esta acción devuelve success:true para que StockAutos guarde el estado
// 'paused' localmente. El usuario puede ocultarlo manualmente desde Facebook.
// ─────────────────────────────────────────────────────────────────────────────

const items = $input.all();
const raw = items[0].json;
const data = raw.body || raw;
const externalId = data.externalId;

if (!externalId) {
  throw new Error('externalId es requerido para pausar la publicación.');
}

return [{
  json: {
    success: true,
    externalId: externalId,
    platform: 'facebook',
    action: 'paused',
    message: 'Estado pausado guardado en StockAutos. Ocultá el post manualmente en Facebook si es necesario.',
    pausedAt: new Date().toISOString(),
    note: 'Facebook Graph API no permite ocultar posts de página de forma programática. Para reactivar usá delete_republish.'
  }
}];

// ─────────────────────────────────────────────────────────────────────────────
// REPUBLICAR VEHÍCULO EN FACEBOOK (eliminar + publicar nuevo)
// ─────────────────────────────────────────────────────────────────────────────

const FB_PAGE_ID = $vars.FB_PAGE_ID;
const FB_PAGE_ACCESS_TOKEN = $vars.FB_PAGE_ACCESS_TOKEN;
const BASE_URL = 'https://graph.facebook.com/v21.0';

