  }

  return [{
    json: {
      success: true,
      externalId: postId,
      vehicleId: vehicle.id,
      platform: 'facebook',
      action: 'republished',
      message: 'Publicación republicada exitosamente en Facebook con fecha actualizada',
      republishedAt: new Date().toISOString(),
      photoCount: photos.length,
      postType: photos.length === 1 ? 'single' : 'album'
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      vehicleId: vehicle ? vehicle.id : null,
      platform: 'facebook',
      action: 'delete_republish'
    }
  }];
}
